import{_ as t,o,c as r,ag as a}from"./chunks/framework.Bb4_ZWqO.js";const g=JSON.parse('{"title":"Decisions","description":"Architecture Decision Records for the datasole project.","frontmatter":{"title":"Decisions","order":7,"description":"Architecture Decision Records for the datasole project."},"headers":[],"relativePath":"decisions.md","filePath":"decisions.md"}'),s={name:"decisions.md"};function n(i,e,c,l,d,u){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="architecture-decision-records" tabindex="-1">Architecture Decision Records <a class="header-anchor" href="#architecture-decision-records" aria-label="Permalink to &quot;Architecture Decision Records&quot;">​</a></h1><h2 id="adr-001-single-npm-package-with-conditional-exports" tabindex="-1">ADR-001: Single npm package with conditional exports <a class="header-anchor" href="#adr-001-single-npm-package-with-conditional-exports" aria-label="Permalink to &quot;ADR-001: Single npm package with conditional exports&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> The framework has client, server, and shared code. Options: monorepo with separate packages, single package with subpath exports, or separate repos.</li><li><strong>Decision:</strong> Single npm package with <code>package.json</code> <code>exports</code> map providing <code>datasole</code>, <code>datasole/client</code>, <code>datasole/server</code> subpaths.</li><li><strong>Consequences:</strong> Simpler versioning (one version number), simpler installation (<code>npm install datasole</code>), tree-shaking relies on bundler <code>exports</code> support. Trade-off: larger package download includes both client and server code, though only used portions are bundled.</li></ul><h2 id="adr-002-worker-first-websocket-transport-with-sharedarraybuffer" tabindex="-1">ADR-002: Worker-first WebSocket transport with SharedArrayBuffer <a class="header-anchor" href="#adr-002-worker-first-websocket-transport-with-sharedarraybuffer" aria-label="Permalink to &quot;ADR-002: Worker-first WebSocket transport with SharedArrayBuffer&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> WebSocket I/O on the main thread causes jank during heavy message processing. Web Workers offload I/O but add postMessage serialization overhead.</li><li><strong>Decision:</strong> WebSocket connection lives in a Web Worker. SharedArrayBuffer ring-buffer enables zero-copy data transfer when available; postMessage with Transferable ArrayBuffer as fallback.</li><li><strong>Consequences:</strong> Main thread stays free for UI rendering. Requires COOP/COEP headers for SAB. Adds complexity in worker lifecycle management. Fallback transport ensures compatibility with environments without Workers (React Native, older browsers).</li></ul><h2 id="adr-003-binary-frames-with-pako-compression-end-to-end" tabindex="-1">ADR-003: Binary frames with pako compression end-to-end <a class="header-anchor" href="#adr-003-binary-frames-with-pako-compression-end-to-end" aria-label="Permalink to &quot;ADR-003: Binary frames with pako compression end-to-end&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> JSON text frames are human-readable but wasteful. WebSocket per-message-deflate is CPU-intensive on the server for many connections.</li><li><strong>Decision:</strong> Custom binary frame envelope (opcode + correlation ID + payload length + payload). Application-level pako compression above a configurable threshold (256 bytes). Same codec on client (in-worker) and server.</li><li><strong>Consequences:</strong> 60-80% smaller payloads than raw JSON. Compression runs in the worker thread (no main-thread CPU cost). Per-message-deflate is disabled. Trade-off: frames are not human-readable in browser DevTools without a decoder.</li></ul><h2 id="adr-004-json-patch-rfc-6902-for-state-synchronization" tabindex="-1">ADR-004: JSON Patch (RFC 6902) for state synchronization <a class="header-anchor" href="#adr-004-json-patch-rfc-6902-for-state-synchronization" aria-label="Permalink to &quot;ADR-004: JSON Patch (RFC 6902) for state synchronization&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> State sync options: CRDTs (complex, large library), OT (complex, server-centric), proprietary binary diff (non-standard), or JSON Patch (standard, simple).</li><li><strong>Decision:</strong> Use RFC 6902 JSON Patch for server-to-client state diffs. <code>fast-json-patch</code> library for production; minimal custom impl in shared/diff as fallback.</li><li><strong>Consequences:</strong> Standard, debuggable patches. Smaller than full state snapshots for incremental changes. Trade-off: not as bandwidth-efficient as binary diffs for large arrays; no conflict resolution (server is authoritative).</li></ul><h2 id="adr-005-pluggable-state-backends-via-interface" tabindex="-1">ADR-005: Pluggable state backends via interface <a class="header-anchor" href="#adr-005-pluggable-state-backends-via-interface" aria-label="Permalink to &quot;ADR-005: Pluggable state backends via interface&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> Different deployments need different persistence: in-memory for dev, Redis for multi-process, Postgres for persistence.</li><li><strong>Decision:</strong> <code>StateBackend</code> interface with get/set/delete/subscribe/publish. Built-in: MemoryBackend (default), RedisBackend (optional peer dep), PostgresBackend (optional peer dep). Interface is public for custom backends.</li><li><strong>Consequences:</strong> Clean separation of state management from transport. Optional peer deps keep the core lightweight. Trade-off: each backend must implement pub/sub semantics, which is non-trivial for SQL databases.</li></ul><h2 id="adr-006-rollup-for-multi-target-bundling" tabindex="-1">ADR-006: Rollup for multi-target bundling <a class="header-anchor" href="#adr-006-rollup-for-multi-target-bundling" aria-label="Permalink to &quot;ADR-006: Rollup for multi-target bundling&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> Need IIFE + ESM + CJS client bundles, a worker bundle, and server CJS + ESM bundles. Options: esbuild (fast, less tree-shaking control), tsup (esbuild wrapper), webpack (heavy), Rollup (mature, best tree-shaking).</li><li><strong>Decision:</strong> Rollup with @rollup/plugin-typescript, @rollup/plugin-node-resolve, @rollup/plugin-commonjs, @rollup/plugin-terser, @rollup/plugin-replace.</li><li><strong>Consequences:</strong> Superior tree-shaking for minimal client bundles. Multi-output from single config. Build is slower than esbuild but acceptable. Trade-off: Rollup configuration is verbose for complex multi-target setups.</li></ul><h2 id="adr-007-vitest-for-unit-tests" tabindex="-1">ADR-007: Vitest for unit tests <a class="header-anchor" href="#adr-007-vitest-for-unit-tests" aria-label="Permalink to &quot;ADR-007: Vitest for unit tests&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> Need a test runner with native ESM and TypeScript support. Options: Jest (requires ts-jest/transform config), Vitest (native ESM, native TS, same API as Jest).</li><li><strong>Decision:</strong> Vitest with @vitest/coverage-v8 for coverage.</li><li><strong>Consequences:</strong> Zero configuration for TypeScript. Fast watch mode with HMR. Same describe/it/expect API as Jest. Trade-off: newer ecosystem, fewer plugins than Jest.</li></ul><h2 id="adr-008-playwright-for-e2e-tests" tabindex="-1">ADR-008: Playwright for e2e tests <a class="header-anchor" href="#adr-008-playwright-for-e2e-tests" aria-label="Permalink to &quot;ADR-008: Playwright for e2e tests&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> Need headless browser automation to test the production IIFE bundle. Options: Puppeteer (Chrome only), Cypress (own runner, heavy), Playwright (multi-browser, lightweight, good API).</li><li><strong>Decision:</strong> Playwright with Chromium for e2e tests. Tests load the production build via script tags and assert functional correctness + capture console logs and performance metrics.</li><li><strong>Consequences:</strong> Tests validate the actual production artifact. Console error detection catches runtime issues. Performance metrics (page.evaluate + Performance API) enable regression tracking. Trade-off: requires browser binary download in CI.</li></ul><h2 id="adr-009-framework-agnostic-client-with-no-runtime-framework-deps" tabindex="-1">ADR-009: Framework-agnostic client with no runtime framework deps <a class="header-anchor" href="#adr-009-framework-agnostic-client-with-no-runtime-framework-deps" aria-label="Permalink to &quot;ADR-009: Framework-agnostic client with no runtime framework deps&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> The client must work with React, Vue 3, Svelte, React Native, and vanilla JS. Options: provide framework-specific wrappers, or keep the core framework-free.</li><li><strong>Decision:</strong> <code>DatasoleClient</code> is a plain TypeScript class with no framework imports. Returns plain objects compatible with any reactivity system. Framework-specific hooks/composables can be built on top but are not part of the core.</li><li><strong>Consequences:</strong> Maximum compatibility. No framework-specific dependencies in the client bundle. Trade-off: users must write their own integration glue (a few lines per framework).</li></ul><h2 id="adr-010-default-websocket-path-ds" tabindex="-1">ADR-010: Default WebSocket path <code>/__ds</code> <a class="header-anchor" href="#adr-010-default-websocket-path-ds" aria-label="Permalink to &quot;ADR-010: Default WebSocket path `/__ds`&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> Need a default path for the WebSocket endpoint that is unlikely to conflict with application routes.</li><li><strong>Decision:</strong> Default path is <code>/__ds</code> (double-underscore prefix convention for framework internals, &quot;ds&quot; for datasole). Configurable via <code>DatasoleClientOptions.path</code> and <code>DatasoleServerOptions.path</code>.</li><li><strong>Consequences:</strong> Avoids collision with common paths like <code>/ws</code>, <code>/socket</code>, <code>/api</code>. The double-underscore convention signals &quot;framework internal&quot;. Trade-off: slightly unconventional, but memorable and short.</li></ul><h2 id="adr-011-pluggable-concurrency-models-async-thread-thread-pool-process" tabindex="-1">ADR-011: Pluggable concurrency models (async / thread / thread-pool / process) <a class="header-anchor" href="#adr-011-pluggable-concurrency-models-async-thread-thread-pool-process" aria-label="Permalink to &quot;ADR-011: Pluggable concurrency models (async / thread / thread-pool / process)&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> Different deployment scenarios benefit from different concurrency models. Chat apps need lightweight async per-connection; CPU-heavy game logic benefits from thread-per-connection; high-throughput API gateways need pooled threads; and multi-tenant isolation may require process-per-connection with serialized IPC.</li><li><strong>Decision:</strong> <code>ConcurrencyStrategy</code> interface with four implementations: <code>AsyncStrategy</code> (default Node.js event loop, no isolation), <code>ThreadStrategy</code> (new <code>worker_threads</code> per connection), <code>ThreadPoolStrategy</code> (fixed thread pool with least-connections assignment, <strong>default</strong>), and <code>ProcessStrategy</code> (child_process fork with serialized packet forwarding). All RPC, events, and messages are 1:1 mapped from a connected WebSocket to its assigned worker. The main process handles WebSocket I/O and dispatches serialized frames. Selection via <code>DatasoleServerOptions.concurrency.model</code>. Cluster-friendly: no shared mutable state in the main process beyond the connection registry—compatible with <code>pm2 cluster</code> mode out of the box.</li><li><strong>Consequences:</strong> Maximum flexibility for different workload profiles. Thread-pool default gives good isolation without fork overhead. Trade-off: thread/process strategies add serialization cost for frame forwarding; process strategy doubles memory per connection.</li></ul><h2 id="adr-012-rate-limiting-with-pluggable-backends" tabindex="-1">ADR-012: Rate limiting with pluggable backends <a class="header-anchor" href="#adr-012-rate-limiting-with-pluggable-backends" aria-label="Permalink to &quot;ADR-012: Rate limiting with pluggable backends&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> WebSocket servers need protection against abusive clients. Unlike HTTP rate limiting (well-served by existing middleware), persistent connections require per-connection, per-method rate limiting at the frame level.</li><li><strong>Decision:</strong> <code>RateLimiter</code> interface with <code>check</code>/<code>consume</code>/<code>reset</code>. Two built-in implementations: <code>MemoryRateLimiter</code> (sliding-window counters, suitable for single-process) and <code>RedisRateLimiter</code> (atomic INCR+EXPIRE, shares the same Redis connection as the state backend, suitable for clustered deployments). Configurable per-method rules via <code>RateLimitConfig.rules</code> map. Default: 100 requests/minute/connection.</li><li><strong>Consequences:</strong> Frame-level rate limiting prevents abuse without dropping the WebSocket connection. Redis backend enables consistent limiting across a pm2 cluster. Trade-off: per-frame overhead (one Map lookup or Redis round-trip).</li></ul><h2 id="adr-013-connectioncontext-as-shared-per-connection-state-bag" tabindex="-1">ADR-013: ConnectionContext as shared per-connection state bag <a class="header-anchor" href="#adr-013-connectioncontext-as-shared-per-connection-state-bag" aria-label="Permalink to &quot;ADR-013: ConnectionContext as shared per-connection state bag&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> Multiple subsystems (RPC handlers, event handlers, rate limiters, session managers) need access to per-connection information: auth identity, metadata from upgrade headers, and arbitrary user-set state. Threading the auth result through every callback is ergonomically poor.</li><li><strong>Decision:</strong> <code>ConnectionContext</code> interface, instantiated once per connection from the upgrade auth result, passed as part of <code>RpcContext</code> and available to event handlers. Provides typed <code>get&lt;T&gt;/set/delete</code> for arbitrary state, plus immutable <code>auth</code>, <code>userId</code>, <code>metadata</code>, <code>tags</code>.</li><li><strong>Consequences:</strong> Clean, single object for all per-connection state. Auth data from upgrade headers is automatically populated. Custom middleware can enrich context via <code>set()</code>. Trade-off: mutable bag can accumulate unbounded state if not disciplined.</li></ul><h2 id="adr-014-session-manager-with-configurable-persistence-flush" tabindex="-1">ADR-014: Session manager with configurable persistence flush <a class="header-anchor" href="#adr-014-session-manager-with-configurable-persistence-flush" aria-label="Permalink to &quot;ADR-014: Session manager with configurable persistence flush&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> Users reconnecting after network drops should not lose accumulated state. Full state persistence after every mutation is wasteful. Change streams are needed for external event-driven systems.</li><li><strong>Decision:</strong> <code>SessionManager</code> wraps the <code>StateBackend</code> with per-user in-memory session maps. Dirty writes accumulate and flush to persistence either (a) when a configurable threshold is reached (<code>flushThreshold</code>, default 10 mutations), or (b) on a periodic timer (<code>flushIntervalMs</code>, default 5s), or (c) on explicit <code>flushUser()</code>/<code>flushAll()</code>. Flush triggers <code>backend.publish()</code> which feeds the existing change-stream/subscription mechanism. <code>snapshot()</code>/<code>restore()</code> on reconnect hydrate from persistence.</li><li><strong>Consequences:</strong> Reconnections are seamless with minimal persistence I/O. Change streams integrate with existing <code>StateBackend.subscribe()</code>. Trade-off: data can be lost between flush intervals if the process crashes; configurable thresholds allow tuning this window per use case.</li></ul><h2 id="adr-015-crdt-support-for-bidirectional-client-↔-server-synchronization" tabindex="-1">ADR-015: CRDT support for bidirectional client ↔ server synchronization <a class="header-anchor" href="#adr-015-crdt-support-for-bidirectional-client-↔-server-synchronization" aria-label="Permalink to &quot;ADR-015: CRDT support for bidirectional client ↔ server synchronization&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> JSON Patch (ADR-004) is server-authoritative, which is ideal for server→client live data. But collaborative editing, shared counters, and multi-client state require conflict-free bidirectional sync.</li><li><strong>Decision:</strong> Built-in CRDT primitives in <code>src/shared/crdt/</code>: <code>LWWRegister&lt;T&gt;</code> (last-writer-wins scalar), <code>PNCounter</code> (positive-negative counter with per-node vector), and <code>LWWMap&lt;T&gt;</code> (last-writer-wins map of registers). All implement a common <code>Crdt&lt;T&gt;</code> interface with <code>apply(op)</code>, <code>merge(state)</code>, <code>state()</code>, and <code>value()</code>. Operations are transmitted as <code>CrdtOperation</code> frames over the binary protocol. Client-side <code>CrdtStore</code> queues local ops for immediate local application + async server sync. Server merges all clients&#39; ops and rebroadcasts the resolved state.</li><li><strong>Consequences:</strong> Enables conflict-free collaborative state (counters, presence, shared documents). Reuses the existing binary frame protocol. Trade-off: CRDTs are eventually consistent—no strong ordering guarantees. Current primitives cover common cases; richer CRDTs (OR-Set, RGA for text) can be added later via the <code>Crdt&lt;T&gt;</code> interface.</li></ul><h2 id="adr-016-syncchannel-with-configurable-flush-strategies" tabindex="-1">ADR-016: SyncChannel with configurable flush strategies <a class="header-anchor" href="#adr-016-syncchannel-with-configurable-flush-strategies" aria-label="Permalink to &quot;ADR-016: SyncChannel with configurable flush strategies&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> Different real-time use cases need different synchronization granularities. A stock ticker needs immediate pushes; a dashboard can batch updates; a form auto-save should debounce.</li><li><strong>Decision:</strong> <code>SyncChannel&lt;T&gt;</code> manages a queue of <code>StatePatch</code> operations with three flush strategies: <code>immediate</code> (flush on every enqueue), <code>batched</code> (flush after N ops or M milliseconds, whichever comes first), and <code>debounced</code> (flush after M ms of inactivity). Channels are created per key via <code>DatasoleServer.createSyncChannel()</code> with direction (<code>server-to-client</code>, <code>client-to-server</code>, <code>bidirectional</code>) and mode (<code>json-patch</code>, <code>crdt</code>, <code>snapshot</code>).</li><li><strong>Consequences:</strong> One API covers all real-time patterns—stock tickers, collaborative editing, form sync, live dashboards. Trade-off: batched/debounced strategies introduce latency; <code>immediate</code> is the default for lowest-latency use cases.</li></ul><h2 id="adr-017-data-flow-patterns-as-composable-primitives" tabindex="-1">ADR-017: Data flow patterns as composable primitives <a class="header-anchor" href="#adr-017-data-flow-patterns-as-composable-primitives" aria-label="Permalink to &quot;ADR-017: Data flow patterns as composable primitives&quot;">​</a></h2><ul><li><strong>Status:</strong> Accepted</li><li><strong>Date:</strong> 2026-03-19</li><li><strong>Context:</strong> The framework must support a mix-and-match set of patterns: RPC, server→client events (broadcast), client→server events, bidirectional events (CRDTs), server→client live data structures (JSON Patch), client→server live data, and combinations thereof. Each pattern has different consistency, latency, and API characteristics.</li><li><strong>Decision:</strong> Data flow patterns are defined as the <code>DataFlowPattern</code> discriminated union. Each pattern is served by a corresponding subsystem: <code>RpcDispatcher</code> for RPC, <code>EventBus</code> for events, <code>SyncChannel</code> with <code>json-patch</code> mode for live data structures, <code>SyncChannel</code> with <code>crdt</code> mode for bidirectional sync. The framework composes these freely—a single connection can use multiple patterns concurrently. The minimum viable set of use cases is: (1) pure RPC, (2) server event broadcast (e.g. stock ticker), (3) client→server RPC + server→client live state for seamless frontend data binding (React/Vue reactive model backed by server-side state).</li><li><strong>Consequences:</strong> Users pick only the patterns they need. Composability avoids framework lock-in to a single paradigm. Trade-off: more concepts to learn, but each is independently useful and well-documented.</li></ul>',35)])])}const p=t(s,[["render",n]]);export{g as __pageData,p as default};
